var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0010: <color=#ffd34c>한소림</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0010：<color=#ffd34c>ハネダ・ミズキ</color>","ENG":"[[","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0010: <color=#ffd34c>琳</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เริ่มการทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข WR002M0010: <color=#ffd34c>ฮัน โซริม</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số WR002M0010: <color=#ffd34c>Han Sorim</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>     \\nCCN No. WR002M0010: <color=#ffd34c>小琳</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. WR002M0010: <color=#ffd34c>Han Sorim</color>","FRA":"AEGIS 8\xA0PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. WR002M0010\xA0: <color=#ffd34c>Han Sorim</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"뭘 그렇게 뚫어져라 보고 있나?","JPN":"何をそんなに見ているのだね？","ENG":"What are you staring at?","TWN":"你一直盯著那個看做什麼？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"재미있는 일이라도 있나?","JPN":"何か面白いことでも？","ENG":"Is there anything interesting?","TWN":"有什麼有趣的事情嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......아, 오셨군요.","JPN":"……あっ、いらっしゃいましたか。","ENG":"Oh, you're here,","TWN":"……啊，您來了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"실은 지난 번에 현장 학습 명목으로 작전에 참가한 관리국 아카데미 학생들 중에 특이한 케이스가 있어서 말이죠.","JPN":"実は、先日現場実習の名目で作戦に加わった管理局カウンターアカデミーの\\n生徒の中に、変わったケースの子がいまして。","ENG":"There was a unique case amongst the Administration Academy students who participated in the previous mission as part of their field trip.","TWN":"其實是上次以現場學習為名義，參加作戰的管理局學院學生中，有個特別的案例。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네가 특이하다고 말할 정도라면 정말 특이하긴 한 모양이군.","JPN":"君が変わっていると言うほどなら、本当に変わっているのだろうな。","ENG":"If you're saying that she's unique, that student must really be special.","TWN":"你說特別的話，那就是真的很特別了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"대체 어떤 친구이길래 그러나?","JPN":"いったいどんな生徒なんだ？","ENG":"Who are we talking about?","TWN":"到底是怎麼樣的朋友？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"관리국 카운터 아카데미 중등부에 재학중인 한소림이라는 학생입니다.","JPN":"管理局カウンターアカデミー中等部に在学中の、\\nハネダ・ミズキという生徒です。","ENG":"Her name is Han Sorim. A junior high student in the Administration Counter Academy.","TWN":"在管理局學院的國中部中，有一個叫韓蕭林的學生。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"같은 중등부에 재학중인 양하림, 고등부의 조호진 학생과 화이트 래빗이라는 동물 구조 동아리를 운영하고 있죠.","JPN":"同じく中等部に在学中のホシノ・ウサギ、高等部のイトウ・マユミという\\n生徒と共に、ホワイトラビットという動物救護サークルを運営しています。","ENG":"She's part of the White Rabbit animal rescue club along with Yang Harim, who is also in junior high, and Cho Hojin, who is in high school.","TWN":"她和同樣是國中部的楊夏琳同學，以及高中部趙鎬眞同學一起經營著一個叫白兔社的動物救助社團。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 기억하고 있네. 귀여운 편지를 보내왔었지.","JPN":"ああ、覚えているぞ。可愛らしい手紙をよこしてきたんだったな。","ENG":"Ah, I remember. They sent us a very cute letter.","TWN":"喔，我記得，她們送來了一封很可愛的信呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이 아이가...... 일종의 망상증을 가지고 있다는 보고서가 있습니다.","JPN":"そのハネダ・ミズキという子ですが……一種の妄想癖を持っているという\\n報告が上がっています。","ENG":"This child... was apparently reported for having some sort of delusional disorder.","TWN":"而那孩子……報告說她有某種妄想症。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"망상증? 어떤 종류의?","JPN":"妄想癖？　どういった類の？","ENG":"Delusional disorder? What kind?","TWN":"妄想症？哪種類型？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"복잡한 의학적 소견서가 첨부되어 있습니다만......","JPN":"複雑な医学的所見書も添付されておりましたが……","ENG":"There was a complex medical note attached to the report...","TWN":"報告還附了一份複雜的醫學證明呢……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"한마디로 줄이면 자신을 베테랑 군인이라고 믿는 카운터 능력자...... 라는군요.","JPN":"一言でまとめるなら、自らをベテラン軍人と信じているカウンター能力者……ということになります。","ENG":"But in summary, she's a Counter who believes herself to be a veteran soldier... is what the note said.","TWN":"用一句話來總結，就是她堅信自己是個老兵……的制裁者。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......그건 정말 특이하군.","JPN":"……それは実に変わっているなぁ。","ENG":"That is indeed unique.","TWN":"……那還真是很特別的呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하지만 베테랑 군인인 카운터가 없는 것도 아니지 않나?","JPN":"しかし、実際にベテラン軍人のカウンターも存在するではないか。何か不都合でもあるのかね？","ENG":"But it's not like there aren't any Counters who are actually veterans.","TWN":"但是，也不是沒有身為老兵的制裁者吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이 경우는 조금 다릅니다. 자신이 카운터가 아닌 일반인이라고 믿고 있거든요.","JPN":"この場合は少しややこしいのです。自らをカウンターではなく、\\n一般人と信じ込んでいるのですから。","ENG":"But it's different in her case. She believes that she's just a normal person, not a Counter.","TWN":"她的情況有點不一樣。她相信自己是普通人，而不是制裁者。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"자신이 가진 신체능력은 당사자의 설명에 따르면 카운터 능력이 아니라 혹독한 훈련을 통해 획득한 초인적인 전투술이라고 합니다.","JPN":"彼女が持つ身体能力は、当人の説明によればカウンター能力ではなく、\\n過酷な訓練を経て獲得した超人級の戦闘術なのだそうです。","ENG":"According to her explanation regarding her incredible physical abilities, she has acquired her superhuman combat skills through harsh training.","TWN":"根據當事人的說詞，她認為自己擁有的身體能力不是制裁者的能力，而是通過嚴苛訓練，獲得了超人的戰鬥技巧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};